  ('elementary-0c700c30-moex-00323', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-932665b2', 'sub-elementary-0c700c30-03', NULL, 'single_choice', '關於負偏態分配（negativelyskeweddistribution）資料，下列敘述何者正確？', '["平均值大於或等於中位數", "平均值小於或等於中位數", "平均值大於眾數", "中位數大於眾數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "714e6cc78a19", "answer_pdf_sha1": "21c652325cc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "統計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
